import json
import sys

file_path = "/Users/SamuelvonBaussnern/proj/50_priv/iDSACompanion/docs/sample_heros/Boronmir Siebenfeld von Greifenfurt.json"

with open\(file_path, 'r'\) as f:
    data = json.load\(f\)

print\("\\n=== ATTRIBUTES \(attr\) ==="\)
for key, value in sorted\(data['attr'].items\(\)\):
    print\(f"  {key}: {value}"\)

print\("\\n=== COMBAT TECHNIQUES \(ct\) ==="\)
for ct_id, ct_data in sorted\(data['ct'].items\(\)\):
    print\(f"  {ct_id}: {ct_data}"\)

print\("\\n=== ACTIVATABLE \(Advantages/Disadvantages/Special Abilities\) ==="\)
for key, values in sorted\(data['activatable'].items\(\)\):
    print\(f"\\n  {key}:"\)
    if isinstance\(values, list\):
        for item in values:
            print\(f"    - {item}"\)
    elif isinstance\(values, dict\):
        for id_key, id_val in sorted\(values.items\(\)\):
            if isinstance\(id_val, dict\):
                print\(f"    {id_key}: tier={id_val.get\('tier'\)}"\)
            else:
                print\(f"    {id_key}: {id_val}"\)

print\("\\n=== DERIVED VALUES \(rv\) ==="\)
print\(f"  {data['rv']}"\)

print\("\\n=== TALENTS \(sample\) ==="\)
talents = data['talents']
print\(f"  Total talents: {len\(talents\)}"\)
for talent_id in list\(talents.keys\(\)\)[:5]:
    print\(f"  {talent_id}: {talents[talent_id]}"\)
